using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class ShoppingListConfiguration : IEntityTypeConfiguration<ShoppingList>{public void Configure(EntityTypeBuilder<ShoppingList> builder){builder.ToTable("shopping_lists");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("list_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.TotalEstimatedMxn).HasColumnType("decimal(10,2)");builder.Property(e => e.TotalEstimatedCostMxn).HasColumnType("decimal(10,2)");builder.Property(e => e.CostBreakdown).HasColumnType("jsonb");builder.HasOne(e => e.Group).WithMany().HasForeignKey(e => e.GroupId).OnDelete(DeleteBehavior.Cascade);builder.HasOne(e => e.BudgetMode).WithMany().HasForeignKey(e => e.BudgetModeId);builder.HasIndex(e => new { e.GroupId, e.WeekStartDate });}}
